#include <vector>
#include <string>

std::string Strongest_Extension(const std::string& class_name, const std::vector<std::string>& extensions) {
    int max_strength = INT_MIN;
    std::string strongest_extension;

    for (const auto& ext : extensions) {
        int CAP = 0, SM = 0;
