public class StrongestExtension {
    public static String strongestExtension(String className, String[] extensions) {
        int maxStrength = Integer.MIN_VALUE;
        String strongestExtension = "";

        for (String ext : extensions) {
            int CAP = 0, SM = 0;
            for (char c : ext.toCharArray()) {
                if (Character.isUpperCase(c)) {
                    CAP++;
                } else if (Character.isLowerCase(c)) {
                    SM++;
                }
            }
            int strength = CAP - SM;
            if (strength > maxStrength) {
                maxStrength = strength;
                strongestExtension = ext;
            }
        }

        return className + "." + strongestExtension;
    }

    public static void main(String[] args) {
        String className = "Slices";
        String[] extensions = {"SErviNGSliCes", "Cheese", "StuFfed"};
        System.out.println(strongestExtension(className, extensions)); // Output: Slices.SErviNGSliCes
    }
}
